'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { ResourceClient } = require('../src/resourceClient');

test('mixed cancellation and a later retry preserve isolation and liveness', async () => {
  const pending = [];
  let calls = 0;
  const client = new ResourceClient((key, signal) => new Promise((resolve, reject) => {
    calls += 1;
    pending.push({ key, resolve });
    signal.addEventListener('abort', () => reject(signal.reason || new Error('aborted')), { once: true });
  }));

  const closed = new AbortController();
  const first = client.get('report', closed.signal);
  const firstRejected = assert.rejects(first);
  const surviving = client.get('report');
  await Promise.resolve();
  closed.abort(new Error('navigation'));
  pending[0].resolve('ready');
  await firstRejected;
  assert.equal(await surviving, 'ready');

  const lone = new AbortController();
  const abandoned = client.get('ephemeral', lone.signal);
  const abandonedRejected = assert.rejects(abandoned);
  await Promise.resolve();
  lone.abort(new Error('timeout'));
  await abandonedRejected;
  const retried = client.get('ephemeral');
  await Promise.resolve();
  pending[pending.length - 1].resolve('recovered');
  assert.equal(await retried, 'recovered');
  assert.equal(calls, 3);
});
